// HTML转义函数
function escapeHtml(text) {
    const div = document.createElement('div');
    div.textContent = text == null ? '' : String(text);
    return div.innerHTML;
}

function escapeHtmlAttribute(value) {
    return String(value == null ? '' : value)
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;')
        .replace(/'/g, '&#39;');
}

function normalizeSafeHttpUrl(url) {
    const normalizedValue = String(url || '').trim();
    if (!normalizedValue) {
        return '';
    }

    try {
        const parsedUrl = new URL(normalizedValue, window.location.origin);
        if (parsedUrl.protocol === 'http:' || parsedUrl.protocol === 'https:') {
            return parsedUrl.toString();
        }
    } catch (error) {
        return '';
    }

    return '';
}

// 跳转到自动回复页面并选择指定账号
function goToAutoReply(accountId) {
    const requestedAccountId = String(accountId || '').trim();
    if (!requestedAccountId) {
        showToast('缺少账号ID，无法跳转到自动回复页面', 'warning');
        return;
    }
    pendingAutoReplyAccountId = requestedAccountId;

    // 切换到自动回复页面
    showSection('auto-reply');

    // 设置账号选择器的值
    setTimeout(() => {
    if (!document.getElementById('auto-reply-section')?.classList.contains('active')) {
        return;
    }
    const accountSelect = document.getElementById('accountSelect');
    if (accountSelect) {
        const hasTargetOption = Array.from(accountSelect.options).some(option => option.value === requestedAccountId);
        if (!hasTargetOption) {
            return;
        }
        accountSelect.value = requestedAccountId;
        pendingAutoReplyAccountId = '';
        // 触发change事件来加载关键词
        loadAccountKeywords();
    }
    }, 100);

    showToast(`已切换到自动回复页面，正在定位账号 "${requestedAccountId}"`, 'info');
}





// 登出功能
async function logout() {
    // 停止销售额摘要定时刷新
    stopSalesSummaryRefreshTimer();
    
    try {
    if (authToken) {
        await fetch('/logout', {
        method: 'POST',
        headers: {
            'Authorization': `Bearer ${authToken}`
        }
    });
    }
    localStorage.removeItem('auth_token');
    localStorage.removeItem('user_info');
    window.location.href = '/';
    } catch (err) {
    console.error('登出失败:', err);
    localStorage.removeItem('auth_token');
    localStorage.removeItem('user_info');
    window.location.href = '/';
    }
}

// 检查认证状态
async function checkAuth() {
    if (!authToken) {
    window.location.href = '/';
    return false;
    }

    try {
    const response = await fetch('/verify', {
        headers: {
        'Authorization': `Bearer ${authToken}`
        }
    });
    const result = await response.json();

    if (!result.authenticated) {
        localStorage.removeItem('auth_token');
        localStorage.removeItem('user_info');
        window.location.href = '/';
        return false;
    }

    localStorage.setItem('user_info', JSON.stringify({
        user_id: result.user_id,
        username: result.username,
        is_admin: result.is_admin === true
    }));

    // 检查是否为管理员，显示管理员菜单和功能
    if (result.is_admin === true) {
        const adminMenuSection = document.getElementById('adminMenuSection');
        if (adminMenuSection) {
        adminMenuSection.style.display = 'block';
        }

        // 显示备份管理功能
        const backupManagement = document.getElementById('backup-management');
        if (backupManagement) {
        backupManagement.style.display = 'block';
        }

        // 显示系统重启功能
        const systemRestartBtn = document.getElementById('system-restart-btn');
        if (systemRestartBtn) {
        systemRestartBtn.style.display = 'inline-block';
        }

        const dashboardHotUpdateGroup = document.getElementById('dashboardHotUpdateGroup');
        if (dashboardHotUpdateGroup) {
        dashboardHotUpdateGroup.style.display = 'none';
        }

        // 显示登录与注册设置
        const loginInfoSettings = document.getElementById('login-info-settings');
        if (loginInfoSettings) {
        loginInfoSettings.style.display = 'flex';
        }
    }

    return true;
    } catch (err) {
    localStorage.removeItem('auth_token');
    localStorage.removeItem('user_info');
    window.location.href = '/';
    return false;
    }
}

// 初始化事件监听
document.addEventListener('DOMContentLoaded', async () => {
    // 首先检查认证状态
    const isAuthenticated = await checkAuth();
    if (!isAuthenticated) return;

    // 初始化侧边栏折叠状态
    initSidebarCollapse();
    // 初始化暗色模式
    initDarkMode();
    // 初始化账号保活诊断事件
    initAboutDiagnosticsEvents();
    // 加载防抖延迟设置
    loadDebounceDelay();
    // 启动验证会话监控
    startCaptchaSessionMonitor();
    // 添加Cookie表单提交
    document.getElementById('addForm').addEventListener('submit', handleManualCookieImport);

    // 添加账号密码登录表单提交
    const passwordLoginForm = document.getElementById('passwordLoginFormElement');
    if (passwordLoginForm) {
        passwordLoginForm.addEventListener('submit', handlePasswordLogin);
    }

    // 增强的键盘快捷键和用户体验
    // textarea 中 Enter 允许换行，Ctrl+Enter 提交
    document.getElementById('newKeyword')?.addEventListener('keydown', function(e) {
    if (e.key === 'Enter' && e.ctrlKey) {
        e.preventDefault();
        addKeyword();
    }
    });

    document.getElementById('newReply')?.addEventListener('keydown', function(e) {
    if (e.key === 'Enter' && e.ctrlKey) {
        e.preventDefault();
        addKeyword();
    }
    });

    // ESC键取消编辑
    document.addEventListener('keydown', function(e) {
    if (e.key === 'Escape' && typeof window.editingIndex !== 'undefined') {
        e.preventDefault();
        cancelEdit();
    }
    });

    // 输入框实时验证和提示
    document.getElementById('newKeyword')?.addEventListener('input', function(e) {
    const value = e.target.value.trim();
    const addBtn = document.querySelector('.add-btn');
    const replyInput = document.getElementById('newReply');

    if (value.length > 0) {
        e.target.style.borderColor = '#10b981';
        // 只要关键词有内容就可以添加，不需要回复内容
        addBtn.style.opacity = '1';
        addBtn.style.transform = 'scale(1)';
    } else {
        e.target.style.borderColor = '#e5e7eb';
        addBtn.style.opacity = '0.7';
        addBtn.style.transform = 'scale(0.95)';
    }
    });

    document.getElementById('newReply')?.addEventListener('input', function(e) {
    const value = e.target.value.trim();
    const keywordInput = document.getElementById('newKeyword');

    // 回复内容可以为空，只需要关键词有内容即可
    if (value.length > 0) {
        e.target.style.borderColor = '#10b981';
    } else {
        e.target.style.borderColor = '#e5e7eb';
    }

    // 按钮状态只依赖关键词是否有内容
    const addBtn = document.querySelector('.add-btn');
    if (keywordInput.value.trim().length > 0) {
        addBtn.style.opacity = '1';
        addBtn.style.transform = 'scale(1)';
    } else {
        addBtn.style.opacity = '0.7';
        addBtn.style.transform = 'scale(0.95)';
    }
    });

    // 初始加载仪表盘
    loadDashboard();

    // 加载菜单设置并应用
    loadMenuSettings();

    // 初始化图片关键词事件监听器
    initImageKeywordEventListeners();

    // 初始化卡券图片文件选择器
    initCardImageFileSelector();

    // 初始化编辑卡券图片文件选择器
    initEditCardImageFileSelector();

    // 初始化工具提示
    initTooltips();

    // 初始化商品搜索功能
    initItemsSearch();

    // 初始化商品搜索界面功能
    initItemSearch();

    // 点击侧边栏外部关闭移动端菜单
    document.addEventListener('click', function(e) {
    const sidebar = document.getElementById('sidebar');
    const toggle = document.querySelector('.mobile-toggle');

    if (window.innerWidth <= 768 &&
        !sidebar.contains(e.target) &&
        !toggle.contains(e.target) &&
        sidebar.classList.contains('show')) {
        sidebar.classList.remove('show');
    }
    });
});

